<!--
        desc: 树
        example:
            <base-tree :list="treeData.list">
                <template #default="{row}">
                </template>
            </base-tree/>
-->
<template>
	<el-tree
		:key="treeKey"
		ref="tree"
		v-bind="$attrs"
		:filter-node-method="filterMethod"
		:props="prop"
		:allow-drag="canDrag"
		:load="loadNode"
		:empty-text="emptyText"
		:draggable="draggable"
		:data="data"
		:icon-class="icon"
		:node-key="uniKey"
		:current-node-key="currentNodeKey"
		highlight-current
		:expand-on-click-node="true"
		@check-change="$emit('handleCheckChange', $event)"
	>
		<template #default="{ node, data:d }">
			<slot :row="assign(d, node)"></slot>
		</template>
	</el-tree>
</template>

<script>
export default {
	name: 'BaseTree',
	inheritAttrs: false,
	props: {
		currentNodeKey: {
			type: String,
			default: () => null,
		},
		uniKey: {
			type: String,
			default: () => 'id',
		},
		chooseFirstNode: {
			type: Boolean,
			default: () => false,
		},
		prop: {
			type: Object,
			default: () => {
				return {
					children: 'children',
					label: 'label',
				};
			},
		},
		icon: {
			type: String,
			default: () => '',
		},
		propFilterMethod: {
			type: Function,
			default: () => null,
		},
		filterValue: {
			type: String,
			default: () => '',
		},
		treeKey: {
			type: String,
			default: () =>
				Math.random()
					.toString(16)
					.substr(2),
		},
		canDrag: {
			type: Function,
			default: () => () => false,
		},
		draggable: {
			type: Boolean,
			default: () => false,
		},
		emptyText: {
			type: String,
			default: () => '暂无数据',
		},
		list: {
			type: Array,
			default: () => [],
		},
	},
	data() {
		return {};
	},
	computed: {
		data() {
			return this.list;
		},
	},
	watch: {
		filterValue(val) {
			this.$refs.tree.filter(val);
		},
		list: {
			// immediate: true,
			deep: true,
			handler(newVal) {
				if (newVal?.length > 0) {
					if (this.chooseFirstNode) {
						this.$nextTick(() => {
							const firstItem = this.deepFindFirst(newVal);
							this.$emit('first', firstItem);
							this.currentNodeKey = firstItem[this.uniKey];
							this.refresh();
						});
					}
				}
			},
		},
	},
	methods: {
		//
		refresh() {
			this.treeKey = Math.random()
				.toString(16)
				.substr(2);
		},
		deepFindFirst(data = []) {
			for (let i = 0, len = data.length; i < len; i += 1) {
				if (i === 0) {
					if (data[i]?.children?.length > 0) {
						return this.deepFindFirst(data[i].children);
					}
					return data[i];
				}
			}
			return null;
		},
		filterMethod(value, data) {
			if (this.propFilterMethod) {
				return this.propFilterMethod(value, data);
			}
			if (!value) {
				return true;
			}
			return data.label.indexOf(value) !== -1;
		},
		loadNode(node, resolve) {
			return resolve(this.$emit('loadNode', node));
		},
		getCheckedNodes() {
			return this.$refs.tree.getCheckedNodes();
		},
		getCheckedKeys() {
			return this.$refs.tree.getCheckedKeys();
		},
		setCheckedKeys(keys) {
			this.$refs.tree.setCheckedKeys(keys);
		},
		resetChecked(keys) {
			this.$refs.tree.setCheckedKeys(keys);
		},
		assign(row, node) {
			row.getNode = () => node;
			return row;
		},
	},
};
</script>

<style></style>
